const input = $input.first().json;
const body = input.body || input;

const server = body.server || 'unknown-server';
const alertType = body.alert_type || 'unknown';
const metric = body.metric || 'unknown';
const value = parseFloat(body.value) || 0;
const threshold = parseFloat(body.threshold) || 80;
const service = body.service || 'unknown-service';

// Classify priority based on alert type and severity
let priority = 'P3';
let recommendation = 'Log only';
let autoAction = null;

const alertConfig = {
  'disk_usage': {
    p1Threshold: 95,
    p2Threshold: 85,
    p3Action: 'Log and monitor',
    p2Action: 'Clean temp files',
    p1Action: 'Archive old logs + alert admin'
  },
  'memory_usage': {
    p1Threshold: 95,
    p2Threshold: 80,
    p3Action: 'Log and monitor',
    p2Action: 'Restart service',
    p1Action: 'Failover to backup'
  },
  'cpu_usage': {
    p1Threshold: 95,
    p2Threshold: 85,
    p3Action: 'Log and monitor',
    p2Action: 'Scale resources',
    p1Action: 'Emergency scaling + alert'
  },
  'service_down': {
    p1Threshold: 1,
    p2Threshold: 0,
    p3Action: 'Health check',
    p2Action: 'Auto-restart service',
    p1Action: 'Failover to DR site'
  },
  'database_connection': {
    p1Threshold: 1,
    p2Threshold: 0,
    p3Action: 'Log connection issue',
    p2Action: 'Reset connection pool',
    p1Action: 'Failover to replica'
  }
};

const config = alertConfig[alertType] || {
  p1Threshold: 95,
  p2Threshold: 80,
  p3Action: 'Log only',
  p2Action: 'Auto-remediate',
  p1Action: 'Requires approval'
};

if (value >= config.p1Threshold) {
  priority = 'P1';
  recommendation = config.p1Action;
} else if (value >= config.p2Threshold) {
  priority = 'P2';
  recommendation = config.p2Action;
  autoAction = config.p2Action;
} else {
  priority = 'P3';
  recommendation = config.p3Action;
  autoAction = config.p3Action;
}

const alertId = 'ITA-' + Date.now().toString(36).toUpperCase();

return {
  json: {
    alertId,
    priority,
    server,
    alertType,
    metric,
    value,
    threshold,
    service,
    recommendation,
    autoAction,
    createdAt: new Date().toISOString()
  }
};
